
import zlib, base64, os

data = ""
k = 119

def copy_to_clipboard():
    try:
        decoded = base64.b64decode(data)
        decrypted = bytes([b ^ k for b in decoded])
        lua_code = zlib.decompress(decrypted).decode('utf-8')
        
        # Proses copy ke clipboard Windows
        os.system('echo | set /p="' + lua_code.replace('"', '^"') + '" | clip')
        
        print("------------------------------------------")
        print("BERHASIL! SCRIPT SUDAH DI-COPY.")
        print("Silahkan PASTE (Ctrl+V) di Executor kamu.")
        print("------------------------------------------")
        input("Tekan Enter untuk keluar...")
    except Exception as e:
        print("Terjadi kesalahan.")
        input()

if __name__ == "__main__":
    copy_to_clipboard()
